# Base geometry module - defines foundational types
from shapes import Shape, Color

@abstract
class GeometricObject:
    _name: str

    def __init__(self, name: str):
        self._name = name

    @abstract
    def area(self) -> float:
        pass

    @abstract
    def perimeter(self) -> float:
        pass

    property get name(self) -> str:
        return self._name

    def describe(self) -> str:
        return f"{self.name}: area={self.area()}, perimeter={self.perimeter()}"

interface IDrawable:
    def draw(self) -> str
    def set_color(self, color: Color) -> None

