# Shapes module - concrete shape implementations
# No imports from other modules to avoid circular dependencies

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

@abstract
class Shape:
    color: Color
    center: Point

    def __init__(self, color: Color, center: Point):
        self.color = color
        self.center = center

    @abstract
    def area(self) -> float:
        pass

    @abstract
    def perimeter(self) -> float:
        pass

    @virtual
    def get_description(self) -> str:
        return f"Shape at ({self.center.x}, {self.center.y})"

