# Concrete shapes module - implements drawable shapes
from shapes import Shape, Color, Point
from geometry import IDrawable

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, radius: float, color: Color, center: Point):
        super().__init__(color, center)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def get_description(self) -> str:
        return f"Circle(r={self.radius}) at ({self.center.x}, {self.center.y})"

    def draw(self) -> str:
        return f"Drawing circle with radius {self.radius}"

    def set_color(self, color: Color) -> None:
        self.color = color

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color, center: Point):
        super().__init__(color, center)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def get_description(self) -> str:
        return f"Rectangle({self.width}x{self.height}) at ({self.center.x}, {self.center.y})"

    def draw(self) -> str:
        return f"Drawing rectangle {self.width} x {self.height}"

    def set_color(self, color: Color) -> None:
        self.color = color

