# Utility functions for shape operations
from shapes import Shape, Color
from concrete import Circle, Rectangle

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def total_perimeter(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.perimeter()
    return total

def filter_by_color(shapes: list[Shape], color: Color) -> list[Shape]:
    result: list[Shape] = []
    for s in shapes:
        if s.color == color:
            result.append(s)
    return result

def create_circle(radius: float, cx: float, cy: float) -> Circle:
    return Circle(radius, Color.RED, Point(cx, cy))
